55	fz_stream *
56	fz_new_stream(fz_context *ctx, void *state, fz_stream_next_fn *next, fz_stream_drop_fn *drop)
57	{
58		fz_stream *stm = NULL;
59	
60		fz_try(ctx)
61		{
62			stm = fz_malloc_struct(ctx, fz_stream);
63		}
64		fz_catch(ctx)
65		{
66			if (drop)
67				drop(ctx, state);
68			fz_rethrow(ctx);
69		}
70	
71		stm->refs = 1;
72		stm->error = 0;
73		stm->eof = 0;
74		stm->pos = 0;
75	
76		stm->bits = 0;
77		stm->avail = 0;
