190	static fz_stream *
191	fz_open_file_ptr(fz_context *ctx, FILE *file, const char *name, int wide, int del_on_drop)
192	{
193		fz_stream *stm;
194		fz_file_stream *state = NULL;
195		fz_file_stream *state_to_free = NULL;
196	
197		fz_var(state);
198		fz_var(state_to_free);
199	
200	#ifndef _WIN32
201		assert(!wide);
202	#endif
203		fz_try(ctx)
204		{
205			state_to_free = state = fz_malloc_struct(ctx, fz_file_stream);
206			state->file = file;
207	#ifdef _WIN32
208			if (wide)
209			{
210				size_t z = wcslen((const wchar_t *)name)+1;
211				state->filename_w = fz_malloc(ctx, z*2);
212				memcpy(state->filename_w, name, z*2);
213				state->filename = fz_utf8_from_wchar(ctx, (const wchar_t *)name);
214			}
215			else
216	#endif
217			state->filename = fz_strdup(ctx, name);
218			state->del_on_drop = del_on_drop;
219	
220			state_to_free = NULL;
221			stm = fz_new_stream(ctx, state, next_file, close_and_drop_file);
222			stm->seek = seek_file;
223		}
224		fz_catch(ctx)
225		{
226			if (state == NULL && del_on_drop)
227			{
228				fclose(file);
229	#ifdef _WIN32
230				if (wide)
231					_wunlink((const wchar_t *)name);
232				else
233	#endif
234					unlink(name);
235			}
236			if (state_to_free)
237				close_and_drop_file(ctx, state_to_free);
238			fz_rethrow(ctx);
239		}
240	
241		return stm;
242	}
