320	/* Memory stream */
321	
322	static int next_buffer(fz_context *ctx, fz_stream *stm, size_t max)
323	{
324		return EOF;
325	}
326	
327	static void seek_buffer(fz_context *ctx, fz_stream *stm, int64_t offset, int whence)
328	{
329		int64_t pos = stm->pos - (stm->wp - stm->rp);
330		/* Convert to absolute pos */
331		if (whence == 1)
332		{
333			offset += pos; /* Was relative to current pos */
334		}
335		else if (whence == 2)
336		{
337			offset += stm->pos; /* Was relative to end */
338		}
339	
340		if (offset < 0)
341			offset = 0;
342		if (offset > stm->pos)
343			offset = stm->pos;
344		stm->rp += (int)(offset - pos);
345	}
346	
347	static void drop_buffer(fz_context *ctx, void *state_)
348	{
349		fz_buffer *state = (fz_buffer *)state_;
350		fz_drop_buffer(ctx, state);
351	}
352	
353	fz_stream *
354	fz_open_buffer(fz_context *ctx, fz_buffer *buf)
355	{
356		fz_stream *stm;
357	
358		if (buf == NULL)
359			return NULL;
360	
361		fz_keep_buffer(ctx, buf);
362		stm = fz_new_stream(ctx, buf, next_buffer, drop_buffer);
363		stm->seek = seek_buffer;
364	
365		stm->rp = buf->data;
366		stm->wp = buf->data + buf->len;
367	
368		stm->pos = (int64_t)buf->len;
369	
370		return stm;
371	}
372	
373	fz_stream *
374	fz_open_memory(fz_context *ctx, const unsigned char *data, size_t len)
375	{
376		fz_stream *stm;
377	
378		stm = fz_new_stream(ctx, NULL, next_buffer, NULL);
379		stm->seek = seek_buffer;
380	
381		stm->rp = (unsigned char *)data;
382		stm->wp = (unsigned char *)data + len;
383	
384		stm->pos = (int64_t)len;
385	
386		return stm;
387	}
