27	/* null filter */
28	
29	struct null_filter
30	{
31		fz_stream *chain;
32		uint64_t remain;
33		int64_t offset;
34		unsigned char buffer[4096];
35	};
36	
37	static int
38	next_null(fz_context *ctx, fz_stream *stm, size_t max)
39	{
40		struct null_filter *state = stm->state;
41		uint64_t n;
42	
43		if (state->remain == 0)
44			return EOF;
45	
46		fz_seek(ctx, state->chain, state->offset, 0);
47		n = fz_available(ctx, state->chain, max);
48		if (n == 0)
49			return EOF;
50		if (n > state->remain)
51			n = state->remain;
52		if (n > sizeof(state->buffer))
53			n = sizeof(state->buffer);
54	
55		memcpy(state->buffer, state->chain->rp, n);
56		stm->rp = state->buffer;
57		stm->wp = stm->rp + n;
58		state->chain->rp += n;
59		state->remain -= n;
60		state->offset += n;
61		stm->pos += n;
62		return *stm->rp++;
63	}
64	
65	static void
66	close_null(fz_context *ctx, void *state_)
67	{
68		struct null_filter *state = (struct null_filter *)state_;
69		fz_drop_stream(ctx, state->chain);
70		fz_free(ctx, state);
71	}
72	
73	fz_stream *
74	fz_open_null_filter(fz_context *ctx, fz_stream *chain, uint64_t len, int64_t offset)
75	{
76		struct null_filter *state = fz_malloc_struct(ctx, struct null_filter);
77		state->chain = fz_keep_stream(ctx, chain);
78		state->remain = len;
79		state->offset = offset;
80		return fz_new_stream(ctx, state, next_null, close_null);
81	}
82	
83	/* range filter */
84	
85	struct range_filter
86	{
87		fz_stream *chain;
88		fz_range *ranges;
89		int nranges;
90		int next_range;
91		size_t remain;
92		int64_t offset;
93		unsigned char buffer[4096];
94	};
95	
96	static int
97	next_range(fz_context *ctx, fz_stream *stm, size_t max)
98	{
99		struct range_filter *state = stm->state;
100		size_t n;
101	
102		while (state->remain == 0 && state->next_range < state->nranges)
103		{
104			fz_range *range = &state->ranges[state->next_range++];
105			state->remain = range->length;
106			state->offset = range->offset;
107		}
108	
109		if (state->remain == 0)
110			return EOF;
111		fz_seek(ctx, state->chain, state->offset, 0);
112		n = fz_available(ctx, state->chain, max);
113		if (n > state->remain)
114			n = state->remain;
115		if (n > sizeof(state->buffer))
116			n = sizeof(state->buffer);
117		memcpy(state->buffer, state->chain->rp, n);
118		stm->rp = state->buffer;
119		stm->wp = stm->rp + n;
120		if (n == 0)
121			return EOF;
122		state->chain->rp += n;
123		state->remain -= n;
124		state->offset += n;
125		stm->pos += n;
126		return *stm->rp++;
127	}
128	
129	static void
130	close_range(fz_context *ctx, void *state_)
131	{
132		struct range_filter *state = (struct range_filter *)state_;
133		fz_drop_stream(ctx, state->chain);
134		fz_free(ctx, state->ranges);
135		fz_free(ctx, state);
136	}
137	
138	fz_stream *
139	fz_open_range_filter(fz_context *ctx, fz_stream *chain, fz_range *ranges, int nranges)
140	{
141		struct range_filter *state = NULL;
142	
143		state = fz_malloc_struct(ctx, struct range_filter);
144		fz_try(ctx)
145		{
146			if (nranges > 0)
147			{
148				state->ranges = fz_calloc(ctx, nranges, sizeof(*ranges));
149				memcpy(state->ranges, ranges, nranges * sizeof(*ranges));
150				state->nranges = nranges;
151				state->next_range = 1;
152				state->remain = ranges[0].length;
153				state->offset = ranges[0].offset;
154			}
155			else
156			{
157				state->ranges = NULL;
158				state->nranges = 0;
159				state->next_range = 1;
160				state->remain = 0;
161				state->offset = 0;
162			}
163			state->chain = fz_keep_stream(ctx, chain);
164		}
165		fz_catch(ctx)
166		{
167			fz_free(ctx, state->ranges);
168			fz_free(ctx, state);
169			fz_rethrow(ctx);
170		}
171	
172		return fz_new_stream(ctx, state, next_range, close_range);
173	}
174	
175	/* endstream filter */
176	
177	#define END_CHECK_SIZE 32
178	
179	struct endstream_filter
180	{
181		fz_stream *chain;
182		uint64_t remain;
183		size_t extras, size;
184		int64_t offset;
185		int warned;
186		unsigned char buffer[4096];
187	};
188	
189	static int
190	next_endstream(fz_context *ctx, fz_stream *stm, size_t max)
191	{
192		struct endstream_filter *state = stm->state;
193		size_t n, nbytes_in_buffer, size;
194		unsigned char *rp;
195	
196		if (state->remain == 0)
197			goto look_for_endstream;
198	
199		fz_seek(ctx, state->chain, state->offset, 0);
200		n = fz_available(ctx, state->chain, max);
201		if (n == 0)
202			return EOF;
203		if (n > state->remain)
204			n = state->remain;
205		if (n > sizeof(state->buffer))
206			n = sizeof(state->buffer);
207		memcpy(state->buffer, state->chain->rp, n);
208		stm->rp = state->buffer;
209		stm->wp = stm->rp + n;
210		state->chain->rp += n;
211		state->remain -= n;
212		state->offset += n;
213		stm->pos += n;
214		return *stm->rp++;
215	
216	look_for_endstream:
217		/* We should distrust the stream length, and check for end
218		 * marker before terminating the stream - this is to cope
219		 * with files with duff "Length" values. */
220	
221		/* Move any data left over in our buffer down to the start.
222		 * Ordinarily, there won't be any, but this allows for the
223		 * case where we were part way through matching a stream end
224		 * marker when the buffer filled before. */
225		nbytes_in_buffer = state->extras;
226		if (nbytes_in_buffer)
227			memmove(state->buffer, stm->rp, nbytes_in_buffer);
228		stm->rp = state->buffer;
229		stm->wp = stm->rp + nbytes_in_buffer;
230	
231		/* In most sane files, we'll get "\nendstream" instantly. We
232		 * should only need (say) 32 bytes to be sure. For crap files
233		 * where we overread regularly, don't harm performance by
234		 * working in small chunks. */
235		size = state->size * 2;
236		if (size > sizeof(state->buffer))
237			size = sizeof(state->buffer);
238		state->size = size;
239	
240		/* Read enough data into our buffer to start looking for the 'endstream' token. */
241		fz_seek(ctx, state->chain, state->offset, 0);
242		while (nbytes_in_buffer < size)
243		{
244			n = fz_available(ctx, state->chain, size - nbytes_in_buffer);
245			if (n == 0)
246				break;
247			if (n > size - nbytes_in_buffer)
248				n = size - nbytes_in_buffer;
249			memcpy(stm->wp, state->chain->rp, n);
250			stm->wp += n;
251			state->chain->rp += n;
252			nbytes_in_buffer += n;
253			state->offset += n;
254		}
255	
256		/* Look for the 'endstream' token. */
257		rp = fz_memmem(state->buffer, nbytes_in_buffer, "endstream", 9);
258		if (rp)
259		{
260			/* Include newline (CR|LF|CRLF) before 'endstream' token */
261			if (rp > state->buffer && rp[-1] == '\n') --rp;
262			if (rp > state->buffer && rp[-1] == '\r') --rp;
263			n = rp - state->buffer;
264			stm->eof = 1; /* We're done, don't call us again! */
265		}
266		else if (nbytes_in_buffer > 11) /* 11 covers enough data to detect "\r?\n?endstream" */
267			n = nbytes_in_buffer - 11; /* no endstream, but there is more data */
268		else
269			n = nbytes_in_buffer; /* no endstream, but at the end of the file */
270	
271		/* We have at least n bytes before we hit an end marker */
272		state->extras = nbytes_in_buffer - n;
273		stm->wp = stm->rp + n;
274		stm->pos += n;
275	
276		if (n == 0)
277			return EOF;
278	
279		if (!state->warned)
280		{
281			state->warned = 1;
282			fz_warn(ctx, "PDF stream Length incorrect");
283		}
284		return *stm->rp++;
285	}
286	
287	static void
288	close_endstream(fz_context *ctx, void *state_)
289	{
290		struct endstream_filter *state = (struct endstream_filter *)state_;
291		fz_drop_stream(ctx, state->chain);
292		fz_free(ctx, state);
293	}
294	
295	fz_stream *
296	fz_open_endstream_filter(fz_context *ctx, fz_stream *chain, uint64_t len, int64_t offset)
297	{
298		struct endstream_filter *state;
299	
300		state = fz_malloc_struct(ctx, struct endstream_filter);
301		state->chain = fz_keep_stream(ctx, chain);
302		state->remain = len;
303		state->offset = offset;
304		state->extras = 0;
305		state->size = END_CHECK_SIZE >> 1; /* size is doubled first thing when used */
306	
307		return fz_new_stream(ctx, state, next_endstream, close_endstream);
308	}
309	
310	/* concat filter */
311	
312	struct concat_filter
313	{
314		int max;
315		int count;
316		int current;
317		int pad; /* 1 if we should add whitespace padding between streams */
318		unsigned char ws_buf;
319		fz_stream *chain[1];
320	};
321	
322	static int
323	next_concat(fz_context *ctx, fz_stream *stm, size_t max)
324	{
325		struct concat_filter *state = (struct concat_filter *)stm->state;
326		size_t n;
327	
328		while (state->current < state->count)
329		{
330			/* Read the next block of underlying data. */
331			if (stm->wp == state->chain[state->current]->wp)
332				state->chain[state->current]->rp = stm->wp;
333			n = fz_available(ctx, state->chain[state->current], max);
334			if (n)
335			{
336				stm->rp = state->chain[state->current]->rp;
337				stm->wp = state->chain[state->current]->wp;
338				stm->pos += n;
339				return *stm->rp++;
340			}
341			else
342			{
343				if (state->chain[state->current]->error)
344				{
345					stm->error = 1;
346					break;
347				}
348				state->current++;
349				fz_drop_stream(ctx, state->chain[state->current-1]);
350				if (state->pad)
351				{
352					stm->wp = stm->rp = (&state->ws_buf)+1;
353					stm->pos++;
354					return 32;
355				}
356			}
357		}
358	
359		stm->rp = stm->wp;
360	
361		return EOF;
362	}
363	
364	static void
365	close_concat(fz_context *ctx, void *state_)
366	{
367		struct concat_filter *state = (struct concat_filter *)state_;
368		int i;
369	
370		for (i = state->current; i < state->count; i++)
371		{
372			fz_drop_stream(ctx, state->chain[i]);
373		}
374		fz_free(ctx, state);
375	}
376	
377	fz_stream *
378	fz_open_concat(fz_context *ctx, int len, int pad)
379	{
380		struct concat_filter *state;
381	
382		state = fz_calloc(ctx, 1, sizeof(struct concat_filter) + (len-1)*sizeof(fz_stream *));
383		state->max = len;
384		state->count = 0;
385		state->current = 0;
386		state->pad = pad;
387		state->ws_buf = 32;
388	
389		return fz_new_stream(ctx, state, next_concat, close_concat);
390	}
391	
392	void
393	fz_concat_push_drop(fz_context *ctx, fz_stream *concat, fz_stream *chain)
394	{
395		struct concat_filter *state = (struct concat_filter *)concat->state;
396	
397		if (state->count == state->max)
398		{
399			fz_drop_stream(ctx, chain);
400			fz_throw(ctx, FZ_ERROR_ARGUMENT, "concatenated more streams than promised");
401		}
402	
403		state->chain[state->count++] = chain;
404	}
405	
406	/* ASCII Hex Decode */
407	
408	typedef struct
409	{
410		fz_stream *chain;
411		int eod;
412		unsigned char buffer[256];
413	} fz_ahxd;
414	
415	static inline int iswhite(int a)
416	{
417		switch (a) {
418		case '\n': case '\r': case '\t': case ' ':
419		case '\0': case '\f': case '\b': case 0177:
420			return 1;
421		}
422		return 0;
423	}
424	
425	static inline int ishex(int a)
426	{
427		return (a >= 'A' && a <= 'F') ||
428			(a >= 'a' && a <= 'f') ||
429			(a >= '0' && a <= '9');
430	}
431	
432	static inline int unhex(int a)
433	{
434		if (a >= 'A' && a <= 'F') return a - 'A' + 0xA;
435		if (a >= 'a' && a <= 'f') return a - 'a' + 0xA;
436		if (a >= '0' && a <= '9') return a - '0';
437		return 0;
438	}
439	
440	static int
441	next_ahxd(fz_context *ctx, fz_stream *stm, size_t max)
442	{
443		fz_ahxd *state = stm->state;
444		unsigned char *p = state->buffer;
445		unsigned char *ep;
446		int a, b, c, odd;
447	
448		if (max > sizeof(state->buffer))
449			max = sizeof(state->buffer);
450		ep = p + max;
451	
452		odd = 0;
453	
454		while (p < ep)
455		{
456			if (state->eod)
457				break;
458	
459			c = fz_read_byte(ctx, state->chain);
460			if (c < 0)
461				break;
462	
463			if (ishex(c))
464			{
465				if (!odd)
466				{
467					a = unhex(c);
468					odd = 1;
469				}
470				else
471				{
472					b = unhex(c);
473					*p++ = (a << 4) | b;
474					odd = 0;
475				}
476			}
477			else if (c == '>')
478			{
479				if (odd)
480					*p++ = (a << 4);
481				state->eod = 1;
482				break;
483			}
484			else if (!iswhite(c))
485			{
486				fz_throw(ctx, FZ_ERROR_FORMAT, "bad data in ahxd: '%c'", c);
487			}
488		}
489		stm->rp = state->buffer;
490		stm->wp = p;
491		stm->pos += p - state->buffer;
492	
493		if (stm->rp != p)
494			return *stm->rp++;
495		return EOF;
496	}
497	
498	static void
499	close_ahxd(fz_context *ctx, void *state_)
500	{
501		fz_ahxd *state = (fz_ahxd *)state_;
502		fz_drop_stream(ctx, state->chain);
503		fz_free(ctx, state);
504	}
505	
506	fz_stream *
507	fz_open_ahxd(fz_context *ctx, fz_stream *chain)
508	{
509		fz_ahxd *state = fz_malloc_struct(ctx, fz_ahxd);
510		state->chain = fz_keep_stream(ctx, chain);
511		state->eod = 0;
512		return fz_new_stream(ctx, state, next_ahxd, close_ahxd);
513	}
514	
515	/* ASCII 85 Decode */
516	
517	typedef struct
518	{
519		fz_stream *chain;
520		unsigned char buffer[256];
521		int eod;
522	} fz_a85d;
523	
524	static int
525	next_a85d(fz_context *ctx, fz_stream *stm, size_t max)
526	{
527		fz_a85d *state = stm->state;
528		unsigned char *p = state->buffer;
529		unsigned char *ep;
530		int count = 0;
531		uint32_t word = 0;
532		int c;
533	
534		if (state->eod)
535			return EOF;
536	
537		if (max > sizeof(state->buffer))
538			max = sizeof(state->buffer);
539	
540		ep = p + max;
541		while (p < ep)
542		{
543			c = fz_read_byte(ctx, state->chain);
544			if (c < 0)
545				break;
546	
547			if (c >= '!' && c <= 'u')
548			{
549				if (count == 4)
550				{
551					word = word * 85 + (c - '!');
552	
553					*p++ = (word >> 24) & 0xff;
554					*p++ = (word >> 16) & 0xff;
555					*p++ = (word >> 8) & 0xff;
556					*p++ = (word) & 0xff;
557	
558					word = 0;
559					count = 0;
560				}
561				else
562				{
563					word = word * 85 + (c - '!');
564					count ++;
565				}
566			}
567	
568			else if (c == 'z' && count == 0)
569			{
570				*p++ = 0;
571				*p++ = 0;
572				*p++ = 0;
573				*p++ = 0;
574			}
575	
576			else if (c == '~')
577			{
578				c = fz_read_byte(ctx, state->chain);
579				if (c != '>')
580					fz_warn(ctx, "bad eod marker in a85d");
581	
582				switch (count) {
583				case 0:
584					break;
585				case 1:
586					/* Specifically illegal in the spec, but adobe
587					 * and gs both cope. See normal_87.pdf for a
588					 * case where this matters. */
589					fz_warn(ctx, "partial final byte in a85d");
590					break;
591				case 2:
592					word = word * (85 * 85 * 85) + 0xffffff;
593					*p++ = word >> 24;
594					break;
595				case 3:
596					word = word * (85 * 85) + 0xffff;
597					*p++ = word >> 24;
598					*p++ = word >> 16;
599					break;
600				case 4:
601					word = word * 85 + 0xff;
602					*p++ = word >> 24;
603					*p++ = word >> 16;
604					*p++ = word >> 8;
605					break;
606				}
607				state->eod = 1;
608				break;
609			}
610	
611			else if (!iswhite(c))
612			{
613				fz_throw(ctx, FZ_ERROR_FORMAT, "bad data in a85d: '%c'", c);
614			}
615		}
616	
617		stm->rp = state->buffer;
618		stm->wp = p;
619		stm->pos += p - state->buffer;
620	
621		if (p == stm->rp)
622			return EOF;
623	
624		return *stm->rp++;
625	}
626	
627	static void
628	close_a85d(fz_context *ctx, void *state_)
629	{
630		fz_a85d *state = (fz_a85d *)state_;
631		fz_drop_stream(ctx, state->chain);
632		fz_free(ctx, state);
633	}
634	
635	fz_stream *
636	fz_open_a85d(fz_context *ctx, fz_stream *chain)
637	{
638		fz_a85d *state = fz_malloc_struct(ctx, fz_a85d);
639		state->chain = fz_keep_stream(ctx, chain);
640		state->eod = 0;
641		return fz_new_stream(ctx, state, next_a85d, close_a85d);
642	}
643	
644	/* Run Length Decode */
645	
646	typedef struct
647	{
648		fz_stream *chain;
649		int run, n, c;
650		unsigned char buffer[256];
651	} fz_rld;
652	
653	static int
654	next_rld(fz_context *ctx, fz_stream *stm, size_t max)
655	{
656		fz_rld *state = stm->state;
657		unsigned char *p = state->buffer;
658		unsigned char *ep;
659	
660		if (state->run == 128)
661			return EOF;
662	
663		if (max > sizeof(state->buffer))
664			max = sizeof(state->buffer);
665		ep = p + max;
666	
667		while (p < ep)
668		{
669			if (state->run == 128)
670				break;
671	
672			if (state->n == 0)
673			{
674				state->run = fz_read_byte(ctx, state->chain);
675				if (state->run < 0)
676				{
677					state->run = 128;
678					break;
679				}
680				if (state->run < 128)
681					state->n = state->run + 1;
682				if (state->run > 128)
683				{
684					state->n = 257 - state->run;
685					state->c = fz_read_byte(ctx, state->chain);
686					if (state->c < 0)
687						fz_throw(ctx, FZ_ERROR_FORMAT, "premature end of data in run length decode");
688				}
689			}
690	
691			if (state->run < 128)
692			{
693				while (p < ep && state->n)
694				{
695					int c = fz_read_byte(ctx, state->chain);
696					if (c < 0)
697						fz_throw(ctx, FZ_ERROR_FORMAT, "premature end of data in run length decode");
698					*p++ = c;
699					state->n--;
700				}
701			}
702	
703			if (state->run > 128)
704			{
705				while (p < ep && state->n)
706				{
707					*p++ = state->c;
708					state->n--;
709				}
710			}
711		}
712	
713		stm->rp = state->buffer;
714		stm->wp = p;
715		stm->pos += p - state->buffer;
716	
717		if (p == stm->rp)
718			return EOF;
719	
720		return *stm->rp++;
721	}
722	
723	static void
724	close_rld(fz_context *ctx, void *state_)
725	{
726		fz_rld *state = (fz_rld *)state_;
727		fz_drop_stream(ctx, state->chain);
728		fz_free(ctx, state);
729	}
730	
731	fz_stream *
732	fz_open_rld(fz_context *ctx, fz_stream *chain)
733	{
734		fz_stream *stm;
735		fz_rld *state = fz_malloc_struct(ctx, fz_rld);
736		state->chain = fz_keep_stream(ctx, chain);
737		state->run = 0;
738		state->n = 0;
739		state->c = 0;
740	
741		stm = fz_new_stream(ctx, state, next_rld, close_rld);
742	
743		/* Don't explode RLE compression bombs. */
744		if (chain->next == next_rld)
745		{
746			fz_warn(ctx, "RLE bomb defused");
747			stm->eof = 1;
748		}
749	
750		return stm;
751	}
752	
753	/* RC4 Filter */
754	
755	typedef struct
756	{
757		fz_stream *chain;
758		fz_arc4 arc4;
759		unsigned char buffer[256];
760	} fz_arc4c;
761	
762	static int
763	next_arc4(fz_context *ctx, fz_stream *stm, size_t max)
764	{
765		fz_arc4c *state = stm->state;
766		size_t n = fz_available(ctx, state->chain, max);
767	
768		if (n == 0)
769			return EOF;
770		if (n > sizeof(state->buffer))
771			n = sizeof(state->buffer);
772	
773		stm->rp = state->buffer;
774		stm->wp = state->buffer + n;
775		fz_arc4_encrypt(&state->arc4, stm->rp, state->chain->rp, n);
776		state->chain->rp += n;
777		stm->pos += n;
778	
779		return *stm->rp++;
780	}
781	
782	static void
783	close_arc4(fz_context *ctx, void *state_)
784	{
785		fz_arc4c *state = (fz_arc4c *)state_;
786		fz_drop_stream(ctx, state->chain);
787		fz_free(ctx, state);
788	}
789	
790	fz_stream *
791	fz_open_arc4(fz_context *ctx, fz_stream *chain, unsigned char *key, unsigned keylen)
792	{
793		fz_arc4c *state = fz_malloc_struct(ctx, fz_arc4c);
794		state->chain = fz_keep_stream(ctx, chain);
795		fz_arc4_init(&state->arc4, key, keylen);
796		return fz_new_stream(ctx, state, next_arc4, close_arc4);
797	}
798	
799	/* AES Filter */
800	
801	typedef struct
802	{
803		fz_stream *chain;
804		fz_aes aes;
805		unsigned char iv[16];
806		int ivcount;
807		unsigned char bp[16];
808		unsigned char *rp, *wp;
809		unsigned char buffer[256];
810	} fz_aesd;
811	
812	static int
813	next_aesd(fz_context *ctx, fz_stream *stm, size_t max)
814	{
815		fz_aesd *state = stm->state;
816		unsigned char *p = state->buffer;
817		unsigned char *ep;
818	
819		if (max > sizeof(state->buffer))
820			max = sizeof(state->buffer);
821		ep = p + max;
822	
823		while (state->ivcount < 16)
824		{
825			int c = fz_read_byte(ctx, state->chain);
826			if (c < 0)
827				fz_throw(ctx, FZ_ERROR_FORMAT, "premature end in aes filter");
828			state->iv[state->ivcount++] = c;
829		}
830	
831		while (state->rp < state->wp && p < ep)
832			*p++ = *state->rp++;
833	
834		while (p < ep)
835		{
836			size_t n = fz_read(ctx, state->chain, state->bp, 16);
837			if (n == 0)
838				break;
839			else if (n < 16)
840				fz_throw(ctx, FZ_ERROR_FORMAT, "partial block in aes filter");
841	
842			fz_aes_crypt_cbc(&state->aes, FZ_AES_DECRYPT, 16, state->iv, state->bp, state->bp);
843			state->rp = state->bp;
844			state->wp = state->bp + 16;
845	
846			/* strip padding at end of file */
847			if (fz_is_eof(ctx, state->chain))
848			{
849				int pad = state->bp[15];
850				if (pad < 1 || pad > 16)
851					fz_throw(ctx, FZ_ERROR_FORMAT, "aes padding out of range: %d", pad);
852				state->wp -= pad;
853			}
854	
855			while (state->rp < state->wp && p < ep)
856				*p++ = *state->rp++;
857		}
858	
859		stm->rp = state->buffer;
860		stm->wp = p;
861		stm->pos += p - state->buffer;
862	
863		if (p == stm->rp)
864			return EOF;
865	
866		return *stm->rp++;
867	}
868	
869	static void
870	close_aesd(fz_context *ctx, void *state_)
871	{
872		fz_aesd *state = (fz_aesd *)state_;
873		fz_drop_stream(ctx, state->chain);
874		fz_free(ctx, state);
875	}
876	
877	fz_stream *
878	fz_open_aesd(fz_context *ctx, fz_stream *chain, unsigned char *key, unsigned keylen)
879	{
880		fz_aesd *state = fz_malloc_struct(ctx, fz_aesd);
881		if (fz_aes_setkey_dec(&state->aes, key, keylen * 8))
882		{
883			fz_free(ctx, state);
884			fz_throw(ctx, FZ_ERROR_ARGUMENT, "aes invalid key size (%d)", keylen * 8);
885		}
886		state->ivcount = 0;
887		state->rp = state->bp;
888		state->wp = state->bp;
889		state->chain = fz_keep_stream(ctx, chain);
890		return fz_new_stream(ctx, state, next_aesd, close_aesd);
891	}
